from __future__ import annotations

import streamlit as st


def apply_theme() -> None:
    st.markdown("""
<style>
:root{--bg:#0B0E11;--surface:#181A20;--surface2:#1E2329;--gold:#F3BA2F;--green:#02C076;--red:#F6465D;--text:#F5F5F5;--muted:#A7B0BE;--line:rgba(255,255,255,.09)}
*{box-sizing:border-box}html,body,.stApp{max-width:100%;overflow-x:hidden}.stApp{background:radial-gradient(circle at 10% -10%,rgba(243,186,47,.18),transparent 28%),linear-gradient(180deg,#0B0E11,#06070A);color:var(--text);font-family:-apple-system,BlinkMacSystemFont,Inter,sans-serif}.block-container{width:100%!important;max-width:460px!important;padding:6.7rem .9rem 2rem!important}#MainMenu,footer,header,[data-testid="stToolbar"]{display:none!important}.topbar{position:fixed;top:0;left:50%;transform:translateX(-50%);z-index:9;width:min(460px,100%);padding:.8rem .9rem .45rem;background:rgba(11,14,17,.9);backdrop-filter:blur(18px);border-bottom:1px solid var(--line)}.brand{display:flex;justify-content:space-between;align-items:center;gap:.75rem;font-weight:950;letter-spacing:-.04em}.brand b{color:var(--gold)}.brand small{color:var(--muted);font-size:.68rem;text-align:right}.nav{display:flex;gap:.45rem;overflow-x:auto;max-width:100%;padding:.65rem 0 .25rem;scrollbar-width:none}.nav::-webkit-scrollbar{display:none}.nav a{white-space:nowrap;text-decoration:none;color:var(--muted);font-size:.78rem;font-weight:850;border:1px solid transparent;border-radius:999px;padding:.48rem .78rem}.nav a.active{color:white;background:rgba(243,186,47,.16);border-color:rgba(243,186,47,.3)}.card{min-width:0;border:1px solid var(--line);border-radius:24px;padding:1rem;margin:.75rem 0;background:linear-gradient(145deg,rgba(255,255,255,.065),rgba(255,255,255,.02)),var(--surface);box-shadow:0 18px 50px rgba(0,0,0,.28);animation:up .28s ease both}.hero{background:radial-gradient(circle at 10% 0,rgba(243,186,47,.28),transparent 44%),linear-gradient(145deg,#242832,#11141A)}h1,h2,h3,p{margin-top:0}h1{font-size:clamp(2rem,6vw,3.8rem);line-height:.95}.muted{color:var(--muted);font-size:.84rem}.metric{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:.55rem}.metric div{min-width:0;background:rgba(0,0,0,.22);border:1px solid var(--line);border-radius:17px;padding:.7rem .55rem}.metric b{display:block;font-size:.9rem;overflow-wrap:anywhere}.positive{color:var(--green)}.negative{color:var(--red)}.pill{display:inline-flex;border-radius:999px;padding:.3rem .58rem;background:linear-gradient(135deg,var(--gold),#FFE29A);color:#15110A;font-size:.7rem;font-weight:950}.soft{background:rgba(255,255,255,.055);border:1px solid var(--line);color:white}.row{display:flex;justify-content:space-between;gap:.8rem;align-items:center;min-width:0}.row>*{min-width:0}.logo{width:40px;height:40px;border-radius:50%;flex:0 0 auto}.spark{height:54px;width:100%;margin:.55rem 0}.empty{text-align:left;border-style:dashed}.dashboard-grid{display:grid;grid-template-columns:1fr;gap:.75rem}.dashboard-grid .card{height:100%;margin:0}.dashboard-span-2,.dashboard-span-3{grid-column:auto}.dashboard-section-title{display:flex;justify-content:space-between;align-items:center;gap:.75rem;margin-bottom:.8rem}.mini-list{display:grid;gap:.65rem}.mini-item{padding:.75rem;border:1px solid var(--line);border-radius:18px;background:rgba(0,0,0,.18)}.stButton button,.stDownloadButton button{border-radius:17px!important;border:1px solid rgba(243,186,47,.35)!important;background:linear-gradient(135deg,rgba(243,186,47,.22),rgba(255,255,255,.05))!important;color:white!important;min-height:45px}.app-footer{margin:1.2rem 0 .3rem;padding:1rem;text-align:center;border-top:1px solid var(--line);color:var(--muted);font-size:.76rem}.app-footer b{display:block;color:var(--gold);font-size:.82rem;margin-bottom:.2rem}.stTextInput input,.stNumberInput input,.stTextArea textarea{border-radius:16px!important;background:rgba(255,255,255,.06)!important;color:white!important;border-color:var(--line)!important}@keyframes up{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:none}}
@media(max-width:390px){.block-container{padding-left:.7rem!important;padding-right:.7rem!important}.metric{gap:.38rem}.metric div{padding:.58rem .45rem}}
@media(min-width:768px){.block-container{max-width:900px!important;padding:7.4rem 1.25rem 2.4rem!important}.topbar{width:min(900px,calc(100% - 2.5rem));padding:1rem 1.25rem .6rem;border:1px solid var(--line);border-top:0;border-radius:0 0 26px 26px}.dashboard-grid{grid-template-columns:repeat(2,minmax(0,1fr));gap:1rem}.metric{grid-template-columns:repeat(2,minmax(0,1fr))}.nav{flex-wrap:wrap;overflow-x:hidden}.card{padding:1.1rem}}
@media(min-width:1180px){.block-container{max-width:1180px!important;padding:8rem 1.5rem 2.8rem!important}.topbar{width:min(1180px,calc(100% - 3rem))}.dashboard-grid{grid-template-columns:repeat(3,minmax(0,1fr));gap:1.15rem}.dashboard-span-2{grid-column:span 2}.dashboard-span-3{grid-column:span 3}.metric{grid-template-columns:repeat(3,minmax(0,1fr))}.nav a{font-size:.8rem}.card{padding:1.2rem}}
</style>""", unsafe_allow_html=True)
